description_lines:
General inspection starter: `@tool
extends RefCounted

func run(ctx) -> void:
	var info: Dictionary = ctx.get_import_info()
	ctx.log("path=%s importer=%s class=%s valid=%s" % [ctx.get_asset_path(), info.get("importer", ""), info.get("resource_class", ""), info.get("import_valid", false)])
	ctx.log("options=%d generated=%d dependencies=%d" % [info.get("option_count", 0), info.get("generated_file_count", 0), info.get("dependency_count", 0)])
	var resource: Resource = ctx.get_imported_resource()
	if resource == null:
		ctx.error("Imported resource could not be loaded")
		return`.

Concrete edit example after inspection has confirmed the option is editable and Boolean: `@tool
extends RefCounted

func run(ctx) -> void:
	var option_name: String = "mipmaps/generate"
	if not ctx.has_import_option(option_name):
		ctx.error("Expected import option was not found")
		return
	var before: Variant = ctx.get_import_option(option_name)
	if not (before is bool):
		ctx.error("Expected a Boolean import option")
		return
	ctx.set_import_option(option_name, true)
	ctx.log("staged=%s" % str(ctx.get_staged_changes()))`. Option names and valid values are importer-specific, so inspect rather than copying this texture option to unrelated assets.
